var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"손님, 고래에 대해 알고 계세요?","JPN":"お客様、クジラのこと知ってますか？","ENG":"Dear, wanna know something about whales?","TWN":"客人，你認識鯨魚嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"걔들은 물에 가라앉아 죽지 않으려고 뇌를 절반씩 나눠서 써요.","JPN":"クジラって水中で沈んで死なないように、脳を半分ずつ分けて使ってるんですよ。","ENG":"Whales sleep with half their brain awake so they don't drown and die.","TWN":"鯨魚在水裡時會將大腦分二半使用，才不會溺斃喔。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"한쪽이 자는 동안 한쪽이 숨을 쉬고,","JPN":"片方が眠っている間はもう片方が息をして、","ENG":"So while one brain half sleeps, the other one controls their breathing.","TWN":"當一半在睡覺時，另一半會負責維持呼吸。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":null,"R":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"또 한쪽이 깨어나면 다시 다른 한쪽이 잠들고.","JPN":" 片方が目覚めたらもう片方は眠ってという具合に。","ENG":" And once the sleeping half wakes up, the other one goes to sleep.","TWN":"當一半睡醒後，就再換另一半睡覺。"},"stage":{"bg":"LIFETIME","slots":{"L":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"제가 언제 왜 그러는지 물어 봤더니 글쎄, 숨 못 쉬면 죽으니까 그런대요.","JPN":"以前に理由を聞いてみたんですが、息ができないと死ぬからそうしてるんですって。","ENG":"I once asked why they did this, and someone replied it's because they'll die if they don't breathe.","TWN":"我問為什麼要這樣？牠們說，不呼吸就會死掉呀。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"에엥~ 바보 같아~ 그럼 그냥 물밖으로 나와 살면 되잖아~","JPN":"ええ～ばかみたい～だったら水から出て暮らせばいいのに～","ENG":"Like whaaaat? That's so silly! Then why don't they live outside the water, right?","TWN":"嘖嘖～牠們真傻～只要從水裡出來就好啦～"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"라고 그 때는 꿀꺽했는데, 역시 그런 불편함도 감수할 만큼 바다가 좋다는 뜻이겠죠.","JPN":"って言ってその時はパクっと飲み込んだんですが、やっぱり、そういう不便さがあっても海にいたいってことなんでしょうね。","ENG":"I thought like that, and maybe it just means they like the sea so much that they are willing to overlook that inconvenience.","TWN":"話雖如此，但這也就表示牠們喜歡大海，喜歡到願意忍受這種樣的不方便吧？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"열망이란 건 결국 참을 수 없으니까 열망이거든요.","JPN":"結局のところ、熱望っていうのは我慢できないから熱望なんですもんね。","ENG":"Desire is called desire because it's impossible to resist.","TWN":"渴望就是因為忍不住才叫渴望的嘛。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"맛있는 걸 먹고 싶다, 얏파 하고 싶다, 예뻐지고 싶다…","JPN":"おいしいものが食べたい、ヤッパーしたい、きれいになりたい……","ENG":"I wanna eat something tasty, I wanna Yah'pa, I wanna become pretty...","TWN":"想吃好吃的東西，想開心，想變美…"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"자기는 참을 수 있다고 말하는 사람들은 모두 나쁜 거짓말쟁이들! 참을 수 없으니까 열망이라구요!","JPN":"我慢できるって言う人たちはみんな嘘つきの悪い人です！　我慢できないから熱望なんです！","ENG":"People who claim to be in control of their desires are lying! Because it's impossible to resist your desires!","TWN":"那些說自己可以忍的人全都是騙子！忍不住才叫作渴望！"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"에헤, 실은 동생이랑 떨어져 사는데도 사냥을 도저히 못 참을 때가 있어요.","JPN":"へへっ、実は妹と離れて暮していても狩りだけはどうにも我慢できない時があるんです。","ENG":"Heh, sometimes I have this urge to hunt, even though I live far apart from my sister.","TWN":"嘿嘿，不瞞你說，就算和妹妹分開，還是會有忍不住想狩獵的時候。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEVIA_MILITIA_BUNNY_NULL","text":{"KOREA":"가끔씩, 아주 가끔씩이지만 입 안에서 팔딱거리는 사냥감의 맥동이 떠오르면……","JPN":"ときどき、稀にですけど、口の中で跳ねる獲物の脈動を思い出すと……","ENG":"Sometimes, on rare occasions, when I think about the feeling of my prey's pulse in my mouth, I just...","TWN":"偶爾，真的是很偶爾的時候，當我想起獵物在我嘴裡跳動的感覺……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_BUNNY_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};